// inferred-not-tested:artifact 列 H0 探针未闭合
import Matter from 'https://cdn.jsdelivr.net/npm/matter-js@0/+esm';
const { Engine, Render, Runner, Bodies, Composite, Mouse, MouseConstraint } = Matter;
const el = document.getElementById('world'); el.style.height = '400px';
const engine = Engine.create(); engine.gravity.y = data.gravityY ?? 1;
const opts = s => ({ isStatic: s.isStatic ?? false, restitution: s.restitution ?? 0 });
Composite.add(engine.world, data.bodies.map(s => s.shape === 'circle' ? Bodies.circle(s.x, s.y, s.radius ?? 20, opts(s)) : Bodies.rectangle(s.x, s.y, s.width ?? 40, s.height ?? 40, opts(s))));
const render = Render.create({ element: el, engine, options: { width: el.clientWidth || 640, height: 400, wireframes: false } });
if (data.mouseDrag ?? true) Composite.add(engine.world, MouseConstraint.create(engine, { mouse: Mouse.create(render.canvas) }));
Render.run(render); Runner.run(Runner.create(), engine);

